UPDATE 	#TSECIFRS
SET 	CTR_TYP = 'TRT'
FROM	BTRT..TCONTR C,
		#TSECIFRS S
WHERE 	C.CTR_NF = S.CTR_NF 
AND 	C.UWY_NF = S.UWY_NF 
AND 	C.UW_NT  = S.UW_NT 
AND 	C.END_NT = S.END_NT

UPDATE 	#TSECIFRS
SET 	CTR_TYP = 'FAC'
FROM	BFAC..TCONTR C,
		#TSECIFRS S
WHERE 	C.CTR_NF = S.CTR_NF 
AND 	C.UWY_NF = S.UWY_NF 
AND 	C.UW_NT  = S.UW_NT 
AND 	C.END_NT = S.END_NT

UPDATE 	#TSECIFRS
SET 	CTR_TYP = '???'
WHERE	CTR_TYP IS NULL

INSERT INTO #COUNTCHECK (STEP, STEP_LBL, SELECTCOUNT) SELECT 1, 'CR TRT a modifier', Count(1) FROM #TSECIFRS T, BTRT..TCONTR S WHERE T.CTR_NF = S.CTR_NF AND T.UWY_NF = S.UWY_NF AND T.UW_NT = S.UW_NT AND T.END_NT = S.END_NT AND UPDCR_B = 1
INSERT INTO #COUNTCHECK (STEP, STEP_LBL, SELECTCOUNT) SELECT 2, 'Portfolios TRT a modifier', Count(1) FROM #TSECIFRS T, BTRT..TSECIFRS S WHERE T.CTR_NF = S.CTR_NF AND T.UWY_NF = S.UWY_NF AND T.SEC_NF = S.SEC_NF AND T.UW_NT = S.UW_NT AND T.END_NT = S.END_NT AND UPDIFRSSEG_B = 1
