UPDATE #COUNTCHECK SET TMPSELECTCOUNT = (SELECT Count(1) FROM #TSECIFRS WHERE CTR_TYP = 'TRT' AND UPDCR_B = 1) 			WHERE STEP = 1
UPDATE #COUNTCHECK SET TMPSELECTCOUNT = (SELECT Count(1) FROM #TSECIFRS WHERE CTR_TYP = 'TRT' AND UPDIFRSSEG_B = 1) 	WHERE STEP = 2
