AND		NOT EXISTS (SELECT 1 FROM BTRT..TSECIFRS S WHERE T.CTR_NF = S.CTR_NF AND T.UWY_NF = S.UWY_NF AND T.UW_NT = S.UW_NT AND T.END_NT = S.END_NT AND T.SEC_NF = S.SEC_NF)
UNION
SELECT 	'Sections IFRS TRT inexistantes pour modification Statut', Count(1) FROM #TSECIFRS T WHERE T.UPDINISTS_B = 1  AND T.CTR_TYP = 'TRT' 
AND		NOT EXISTS (SELECT 1 FROM BTRT..TSECIFRS S WHERE T.CTR_NF = S.CTR_NF AND T.UWY_NF = S.UWY_NF AND T.UW_NT = S.UW_NT AND T.END_NT = S.END_NT AND T.SEC_NF = S.SEC_NF)
