AND		NOT EXISTS (SELECT 1 FROM BFAC..TSECIFRS S WHERE T.CTR_NF = S.CTR_NF AND T.UWY_NF = S.UWY_NF AND T.UW_NT = S.UW_NT AND T.END_NT = S.END_NT AND T.SEC_NF = S.SEC_NF)
UNION
SELECT 	'Sections IFRS FAC inexistantes pour modification Profitabilité Initiale', Count(1) FROM #TSECIFRS T WHERE T.UPDINIPRO_B = 1  AND T.CTR_TYP = 'FAC' 
AND		NOT EXISTS (SELECT 1 FROM BFAC..TSECIFRS S WHERE T.CTR_NF = S.CTR_NF AND T.UWY_NF = S.UWY_NF AND T.UW_NT = S.UW_NT AND T.END_NT = S.END_NT AND T.SEC_NF = S.SEC_NF)
UNION
SELECT 	'Sections IFRS FAC inexistantes pour modification Index Rate', Count(1) FROM #TSECIFRS T WHERE T.UPDRATEINDEX_B = 1  AND T.CTR_TYP = 'FAC' 
AND		NOT EXISTS (SELECT 1 FROM BFAC..TSECIFRS S WHERE T.CTR_NF = S.CTR_NF AND T.UWY_NF = S.UWY_NF AND T.UW_NT = S.UW_NT AND T.END_NT = S.END_NT AND T.SEC_NF = S.SEC_NF)
UNION
