IF @gCommit = 'O'
BEGIN
	COMMIT TRAN
	PRINT 'BTRT COMMIT SUCCESSFUL'
END
ELSE
BEGIN
	ROLLBACK TRAN
	PRINT 'BTRT ROLLBACK SUCCESSFUL'
END

fin:
